{
  "mode": "method",
  "tests": [
    {
      "name": "valid_api_requirements",
      "input": {
        "stakeholders": ["product owner", "engineer", "QA"],
        "requirements": {
          "api": "GET /users",
          "acceptance_criteria": "Response includes user data in JSON format"
        }
      },
      "output": {
        "status": "success",
        "message": "Requirements captured successfully"
      },
      "notes": "Validates the ability to capture API requirements from stakeholders."
    },
    {
      "name": "invalid_api_requirements",
      "input": {
        "stakeholders": ["product owner"],
        "requirements": {
          "api": "GET /invalid",
          "acceptance_criteria": "Response includes invalid data"
        }
      },
      "output": {
        "status": "error",
        "message": "Invalid API endpoint"
      },
      "notes": "Tests handling of invalid API requirements."
    },
    {
      "name": "document_api_with_postman",
      "input": {
        "api_details": {
          "name": "User API",
          "method": "GET",
          "endpoint": "/users"
        },
        "tool": "Postman"
      },
      "output": {
        "status": "success",
        "message": "API documented successfully"
      },
      "notes": "Checks the ability to document APIs using Postman."
    },
    {
      "name": "create_sequence_diagram",
      "input": {
        "data_flows": [
          {"source": "User", "target": "API", "action": "request"},
          {"source": "API", "target": "Database", "action": "fetch"},
          {"source": "Database", "target": "API", "action": "return"},
          {"source": "API", "target": "User", "action": "response"}
        ]
      },
      "output": {
        "status": "success",
        "message": "Sequence diagram created"
      },
      "notes": "Validates the ability to create a sequence diagram from data flows."
    },
    {
      "name": "collaborate_on_sprint_planning",
      "input": {
        "sprint": "Sprint 1",
        "tasks": ["Requirement gathering", "Backlog refinement"]
      },
      "output": {
        "status": "success",
        "message": "Sprint planning collaboration successful"
      },
      "notes": "Tests collaboration on sprint planning."
    },
    {
      "name": "edge_case_missing_stakeholder",
      "input": {
        "stakeholders": [],
        "requirements": {
          "api": "GET /users",
          "acceptance_criteria": "Response includes user data"
        }
      },
      "output": {
        "status": "error",
        "message": "No stakeholders provided"
      },
      "notes": "Tests the system's response to missing stakeholders."
    },
    {
      "name": "edge_case_invalid_json_format",
      "input": "{invalid_json}",
      "output": {
        "status": "error",
        "message": "Invalid JSON format"
      },
      "notes": "Checks error handling for invalid JSON input."
    },
    {
      "name": "release_planning_with_azure_pipelines",
      "input": {
        "release": "Version 1.0",
        "tasks": ["Deploy to production", "Monitor performance"]
      },
      "output": {
        "status": "success",
        "message": "Release planning completed"
      },
      "notes": "Validates the ability to support release planning using Azure Pipelines."
    }
  ],
